(window.webpackJsonp=window.webpackJsonp||[]).push([[405],{1032:function(n,r){n.exports='\x3c!-- \r\ntitle: 13-CSS工具\r\nsort: \r\n--\x3e \r\n# CSS工具\r\n\r\n## 导航栏\r\n\r\n### 竖向\r\n\r\n```css\r\nul {\r\n    list-style-type: none;\r\n    margin: 0;\r\n    padding: 0;\r\n    width: 200px;\r\n    background-color: #f1f1f1;\r\n    border: 1px solid #555;\r\n}\r\n\r\nli a {\r\n    display: block;\r\n    /* 将a元素的接触范围映射至框 */\r\n    color: #000;\r\n    padding: 8px 16px;\r\n    text-decoration: none;\r\n}\r\n\r\nli {\r\n    text-align: center;\r\n    border-bottom: 1px solid #555;\r\n}\r\n\r\nli:last-child {\r\n    border-bottom: none;\r\n}\r\n\r\nli a.active {\r\n    background-color: #4CAF50;\r\n    color: white;\r\n}\r\n\r\nli a:hover:not(.active) {\r\n    background-color: #555;\r\n    color: white;\r\n}\r\n```\r\n\r\n### 横向\r\n\r\n```css\r\nul {\r\n    list-style-type: none;\r\n    margin: 0;\r\n    padding: 0;\r\n    overflow: auto;\r\n    background-color: #333;\r\n    position: fixed;\r\n    top: 0;\r\n    width: 100%;\r\n}\r\n\r\nli {\r\n    float: left;\r\n}\r\n\r\nli a {\r\n    display: block;\r\n    color: white;\r\n    text-align: center;\r\n    padding: 14px 16px;\r\n    text-decoration: none;\r\n}\r\n\r\nli a:hover:not(.active) {\r\n    background-color: #111;\r\n}\r\n\r\n.active {\r\n    background-color: #4CAF50;\r\n}\r\n```\r\n\r\n## 下拉菜单\r\n\r\n```html\r\n<style>\r\n.dropdown {\r\n  position: relative;\r\n  display: inline-block;\r\n}\r\n.dropdown-content {\r\n  display: none;\r\n  position: absolute;\r\n  background-color: #f9f9f9;\r\n  min-width: 160px;\r\n  /* 阴影 */\r\n  box-shadow: 0px 8px 16px 0px rgba(0,0,0,0.2);\r\n  /* 内边距 */\r\n  padding: 12px 16px;\r\n}\r\n.dropdown:hover .dropdown-content {\r\n  display: block;\r\n}\r\n</style>\r\n\r\n<div class="dropdown">\r\n  <span>鼠标移动到我这！</span>\r\n  <div class="dropdown-content">\r\n    <p>fzf</p>\r\n    <p>39.106.106.202</p>\r\n  </div>\r\n</div>\r\n```\r\n\r\n```html\r\n\r\n<style>\r\n/* 按钮样式 */\r\n.dropbtn {\r\n    background-color: #4CAF50;\r\n    color: white;\r\n    padding: 16px;\r\n    font-size: 16px;\r\n    border: none;\r\n    cursor: pointer;\r\n}\r\n\r\n.dropdown {\r\n    position: relative;\r\n    display: inline-block;\r\n}\r\n\r\n.dropdown-content {\r\n    display: none;\r\n    position: absolute;\r\n    background-color: #f9f9f9;\r\n    min-width: 160px;\r\n    box-shadow: 0px 8px 16px 0px rgba(0,0,0,0.2);\r\n}\r\n\r\n.dropdown-content a {\r\n    color: black;\r\n    padding: 12px 16px;\r\n    text-decoration: none;\r\n    display: block;\r\n}\r\n\r\n.dropdown-content a:hover {background-color: #f1f1f1}\r\n\r\n.dropdown:hover .dropdown-content {\r\n    display: block;\r\n}\r\n\r\n.dropdown:hover .dropbtn {\r\n    background-color: #3e8e41;\r\n}\r\n</style>\r\n\r\n<div class="dropdown">\r\n  <button class="dropbtn">下拉菜单</button>\r\n  <div class="dropdown-content">\r\n    <a href="//www.runoob.com">菜鸟教程 1</a>\r\n    <a href="//www.runoob.com">菜鸟教程 2</a>\r\n    <a href="//www.runoob.com">菜鸟教程 3</a>\r\n  </div>\r\n</div>\r\n```\r\n\r\n'}}]);